#include <stdlib.h>
#include <math.h>
#include <mmt_core.h>

static unsigned long int limit_ros_dos_per_ms = 0;

void on_load() {
    const char *str = getenv("MMT_SEC_ROS_DOS_LIMIT");
    if (str == NULL) {
        mmt_info("Rule 115: no value of MMT_SEC_ROS_DOS_LIMIT");
        limit_ros_dos_per_ms = 100;
    } else {
        limit_ros_dos_per_ms = strtoul(str, NULL, 0);
    }
    mmt_info("Rule 115: set MMT_SEC_ROS_DOS_LIMIT=%ld", limit_ros_dos_per_ms);
}

static inline int em_is_ros_target_port(double port) {
    int p = (int)port;
    // ROS Master port
    if (p == 11311) return 1;
    // ROS Bridge websocket port
    if (p == 9090) return 1;
    return 0;
}

static inline bool em_ros_check_throughput(const void *data) {
    static int last_ms = 0;
    static unsigned long int counter = 0;

    struct timeval *time = (struct timeval *)data;

    // No limit set
    if (limit_ros_dos_per_ms == 0)
        return true;

    int millisecond = round(time->tv_usec / 1000.0);

    // New window => reset counter
    if (last_ms != millisecond) {
        counter = 0;
        last_ms = millisecond;
    }

    counter++;
    return (counter >= limit_ros_dos_per_ms);
}
